load_mod, load_err = load_module(load_path, "crystal_loader_mod")

def list_callables(mod: types.ModuleType):
    items = []
    for k, v in vars(mod).items():
        if callable(v) and not k.startswith("_"):
            # Skip classes' dunder methods
            items.append(k)
    return items

