# Try to run generator with best-guess signature
def try_run_generator():
    if not gen_mod:
        return {"status":"skipped","reason":"generator not loaded"}
    # Heuristics for signature: (input_path, output_dir) or (export_root, out_dir, types=...)
    candidates = [
        ("generate_crystals", (mock_root, out_crystals)),
        ("build_crystals", (mock_root, out_crystals)),
        ("process_export", (mock_root, out_crystals)),
        ("create_language_crystals", (mock_root, out_crystals)),
        ("run", (mock_root, out_crystals)),
        ("main", (mock_root, out_crystals))
    ]
    for name, args in candidates:
        fn = getattr(gen_mod, name, None)
        if callable(fn):
            try:
                res = fn(*args)
                return {"status":"ok","function":name,"result_summary":str(type(res))[:80], "out_dir":out_crystals}
            except TypeError as te:
                # Try calling with no args
                try:
                    res = fn()
                    return {"status":"ok","function":name,"result_summary":str(type(res))[:80], "out_dir":out_crystals}
                except Exception as e2:
                    return {"status":"error","function":name,"error":f"{te}\nThen calling no-arg failed: {e2}\n{traceback.format_exc()}"}
