# Extract blocks by names using a simple state machine
def extract_named_def(src, name):
    lines = src.splitlines()
    start = None
    block=[]
    indent=None
    for i,l in enumerate(lines):
        if l.strip().startswith(f"def {name}("):
            start = i
            indent = len(l) - len(l.lstrip(" "))
            block.append(l[indent:])
            # capture subsequent lines until next 'def ' at column <= indent
            for j in range(i+1, len(lines)):
                lj = lines[j]
                if lj.strip().startswith("def ") and (len(lj) - len(lj.lstrip(" ")) <= indent):
                    break
                block.append(lj[indent:])
            break
    return "\n".join(block)

